queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?magicians a :Magicians .
    ?magicians p:name ?name .
    ?magicians p:Street_Location ?street_location_f .
    FILTER(STR(?street_location_f) = "Times Square, New York")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?mimes a :Mimes .
    ?mimes p:name ?name .
    ?mimes p:Street_Location ?street_location_f .
    FILTER(STR(?street_location_f) = "Times Square, New York")
    BIND(?name AS ?o0)
  }
}

